        }).catch(function (error) {
            console.log('Failed to clear cache:');
            console.log(error);
        });
    }

    if (document.getElementById("clearIndexedDB").checked) {
        // Clear indexedDB
        indexedDB.databases().then(function (dbs) {
            dbs.forEach(function (db) {
                indexedDB.deleteDatabase(db.name).onsuccess = function () {
                    console.log('IndexedDB cleared successfully:', db.name);
                };
            });
        }).catch(function (error) {
            console.log('Failed to clear indexedDB:');
            console.log(error);
        });
    }

    if (document.getElementById("clearServiceWorkers").checked) {
        // Unregister service workers
        navigator.serviceWorker.getRegistrations().then(function (registrations) {
            if (registrations.length > 0) {
                registrations.forEach(function (registration) {
                    registration.unregister().then(function (boolean) {
                        if (boolean) {
                            console.log('Service worker unregistered successfully:', registration.scope);
                        } else {
                            console.log('Service worker failed to unregister:', registration.scope);
                        }
                    }).catch(function (error) {
